External Knowledge:
- 'most energetic' refers to songs with the highest danceability score; 
- Danceability is a measure of how suitable a song is for dancing, with higher scores indicating more danceable songs.

sql:
SELECT 
    (SELECT COUNT(*) FROM users WHERE is_active = 1) AS number_of_active_users,
    (SELECT COUNT(*) FROM songs) AS total_number_of_songs;

SELECT COUNT(DISTINCT user_id) AS active_users
FROM listening_history
WHERE playback_duration > 600000;

SELECT songs.song_id, songs.title, audio_features.danceability, audio_features.energy
FROM songs
INNER JOIN audio_features ON songs.song_id = audio_features.song_id;
